+            })
+            .collect();
+
+        let i2_matrix: Vec<Vec<f64>> = (0..pushout_dim)
+            .map(|i| {
+                if i >= obj_a.dimension {
+                    let mut row = vec![0.0; obj_b.dimension];
+                    row[i - obj_a.dimension] = 1.0;
+                    row
+                } else {
+                    vec![0.0; obj_b.dimension]
+                }
+            })
+            .collect();
