+    fn forward(&self, node_features: &[Vec<f64>], edges: &[(usize, usize)]) -> Vec<Vec<f64>> {
+        let num_nodes = node_features.len();
+        let mut output = vec![vec![0.0; self.node_dim]; num_nodes];
