+            // Apply restriction map to source
+            let restricted = self.apply_restriction(
+                &node_features[src],
+                edge_idx % self.restriction_weights.len(),
+            );
+
+            // Aggregate at destination
+            for (i, &r) in restricted.iter().enumerate().take(self.node_dim) {
+                output[dst][i] += r;
+            }
+        }
