+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Contradiction {
+    pub belief: ObjectId,
+    pub context: ObjectId,
+    pub reason: String,
+}
+
+/// A violation of sheaf axioms
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct SheafViolation {
+    pub child_context: ObjectId,
+    pub parent_context: ObjectId,
+    pub reason: String,
+}
